#include <iostream>
#include <string>
#include <cstring>

class GameResource {
private:
    std::string name;
    int* data;  // Dynamic resource
    int size;

public:
    // 1. Constructor
    GameResource(std::string n, int s, int defaultValue) : name(n), size(s) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = defaultValue + i;
        }
        std::cout << "Resource '" << name << "' created (size: " << size << ")" << std::endl;
    }

    // 2. Copy Constructor (deep copy)
    GameResource(const GameResource& other) : name(other.name + " (copy)"), size(other.size) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = other.data[i];
        }
        std::cout << "Copy of '" << other.name << "' created" << std::endl;
    }

    // 3. Copy Assignment Operator
    GameResource& operator=(const GameResource& other) {
        std::cout << "Assigning '" << other.name << "' to '" << name << "'" << std::endl;

        // Self-assignment guard
        if (this == &other) {
            return *this;
        }

        // Clean up old data
        delete[] data;

        // Copy new data
        name = other.name + " (assigned)";
        size = other.size;
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = other.data[i];
        }

        return *this;
    }

    // 4. Destructor
    ~GameResource() {
        delete[] data;
        std::cout << "Resource '" << name << "' destroyed" << std::endl;
    }

    void display() const {
        std::cout << name << ": [";
        for (int i = 0; i < size; i++) {
            std::cout << data[i];
            if (i < size - 1) std::cout << ", ";
        }
        std::cout << "]" << std::endl;
    }

    void setValue(int index, int value) {
        if (index >= 0 && index < size) {
            data[index] = value;
        }
    }
};

// Class that breaks the Rule of Three (shows the problem)
class BrokenResource {
private:
    std::string name;
    int* data;
    int size;

public:
    BrokenResource(std::string n, int s) : name(n), size(s) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = i * 10;
        }
        std::cout << "Broken '" << name << "' created" << std::endl;
    }

    // No copy constructor or assignment operator!
    // Uses default shallow copy -> double delete!

    ~BrokenResource() {
        delete[] data;
        std::cout << "Broken '" << name << "' destroyed" << std::endl;
    }

    void display() const {
        std::cout << name << ": [";
        for (int i = 0; i < size; i++) {
            std::cout << data[i];
            if (i < size - 1) std::cout << ", ";
        }
        std::cout << "]" << std::endl;
    }
};

int main() {
    std::cout << "=== The Rule of Three ===" << std::endl;

    std::cout << "\n--- Following the Rule of Three ---" << std::endl;
    GameResource res1("Resource A", 3, 10);
    res1.display();

    // Copy constructor
    GameResource res2 = res1;
    res2.display();

    // Copy assignment
    GameResource res3("Resource C", 2, 100);
    res3.display();
    res3 = res1;
    res3.display();

    // Modifying res1 doesn't affect res2 or res3
    res1.setValue(0, 999);
    std::cout << "\nAfter modifying res1:" << std::endl;
    std::cout << "res1: "; res1.display();
    std::cout << "res2: "; res2.display();
    std::cout << "res3: "; res3.display();

    std::cout << "\n--- Breaking the Rule of Three ---" << std::endl;
    BrokenResource broken1("Broken A", 3);
    broken1.display();

    // THIS CAUSES A DOUBLE DELETE!
    BrokenResource broken2 = broken1;  // Shallow copy!
    broken2.display();

    std::cout << "\n--- The Rule of Three ---" << std::endl;
    std::cout << "If you need:" << std::endl;
    std::cout << "  • Destructor → also need" << std::endl;
    std::cout << "  • Copy Constructor → also need" << std::endl;
    std::cout << "  • Copy Assignment Operator" << std::endl;
    std::cout << "\nRule of Five (C++11): adds" << std::endl;
    std::cout << "  • Move Constructor" << std::endl;
    std::cout << "  • Move Assignment Operator" << std::endl;

    return 0;
}

