#include <iostream>
#include <string>

class ArrayWrapper {
private:
    std::string name;
    int* data;
    int size;

public:
    ArrayWrapper(std::string n, int s, int defaultValue) 
        : name(n), size(s) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = defaultValue;
        }
        std::cout << "Array '" << name << "' created" << std::endl;
    }

    // Copy constructor
    ArrayWrapper(const ArrayWrapper& other) 
        : name(other.name + " (copy)"), size(other.size) {
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = other.data[i];
        }
        std::cout << "Copying array... (") << name << ")" << std::endl;
    }

    // Assignment operator
    ArrayWrapper& operator=(const ArrayWrapper& other) {
        std::cout << "Assigning array..." << std::endl;
        if (this == &other) return *this;

        delete[] data;
        name = other.name + " (assigned)";
        size = other.size;
        data = new int[size];
        for (int i = 0; i < size; i++) {
            data[i] = other.data[i];
        }
        return *this;
    }

    // Destructor
    ~ArrayWrapper() {
        delete[] data;
        std::cout << "Array destroyed: " << name << std::endl;
    }

    void display() const {
        std::cout << name << ": [";
        for (int i = 0; i < size; i++) {
            std::cout << data[i];
            if (i < size - 1) std::cout << ", ";
        }
        std::cout << "]" << std::endl;
    }

    void setValue(int index, int value) {
        if (index >= 0 && index < size) {
            data[index] = value;
        }
    }
};

int main() {
    ArrayWrapper arr1("A", 3, 5);
    ArrayWrapper arr2 = arr1;
    ArrayWrapper arr3("B", 2, 10);

    arr3 = arr1;

    arr1.setValue(0, 999);

    std::cout << "\n=== Arrays ===" << std::endl;
    arr1.display();
    arr2.display();
    arr3.display();

    return 0;
}
